// Check if PR touches pam/azure-migration files
const files = $input.item.json.body?.pull_request?.changed_files || 0;
const branch = $input.item.json.body?.pull_request?.head?.ref || '';
const title = $input.item.json.body?.pull_request?.title || '';
const pr_number = $input.item.json.body?.number;
const repo = $input.item.json.body?.repository?.full_name || '';
return [{ json: { pr_number, repo, branch, title, changed_files: files } }];

const raw = $input.item.json.stdout || '';
const pr = $('Extract PR Details').item.json;
try {
  const d = JSON.parse(raw);
  const agents = d.agents || {};
  const passed = Object.values(agents).filter(v => v === true || v?.status === 'PASS').length;
  const failed = Object.values(agents).filter(v => v === false || v?.status === 'FAIL').length;
  const total = Object.keys(agents).length;
  let body = `## SHIFT Preflight Gate\n\n`;
  body += `**${passed}/${total} agents ready**`;
  if (failed > 0) body += ` — ⚠️ ${failed} agent(s) failing`;
  body += `\n\n`;
  for (const [name, result] of Object.entries(agents)) {
    const icon = (result === true || result?.status === 'PASS') ? '✅' : '❌';
    body += `${icon} Agent ${name}\n`;
  }
  body += `\n_nexus-core preflight (dry-run)_`;
  return [{ json: { ...pr, comment_body: body, all_pass: failed === 0 } }];
} catch (e) {
  return [{ json: { ...pr, comment_body: `## SHIFT Preflight\n\n⚠️ Could not parse preflight output.\n\n\`\`\`\n${raw.substring(0, 500)}\n\`\`\``, all_pass: false } }];
}
